"""
mkt-context layer — Acts chapters 20–21
Output: data/commentary/mkt-context/acts.json
Run: python3 scripts/zc-context-acts-20-21.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output (no duplicate or overwritten entries).
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ACTS_CH = {
"20": {
"1": "<p>Paul's departure from Ephesus follows the riot of Acts 19:23–41. The Macedonian journey mirrors the second missionary journey's Macedonian phase (16:10–17:15) — revisiting communities Paul had planted. The 'exhorting' (parakalesas) of the disciples before departure reflects Paul's consistent pattern of pastoral consolidation before transitions, preparing communities for his absence.</p>",
"2": "<p>The 'those parts' (ta merē ekeina) traversed in Macedonia likely included Philippi, Thessalonica, and Berea. 'Much exhortation' (paraklēsei pollē) summarizes the pastoral content without detail — Luke's interest is the geographical itinerary, not the content of the visits. The three months in Greece (v. 3) would include Corinth, which Paul had established on the second journey and revisited on the third (cf. 2 Cor 12:14; 13:1).</p>",
"3": "<p>The Jewish plot against Paul at Corinth echoes the pattern of opposition Paul faces at the end of each major phase of ministry (cf. 9:23; 14:19; 17:5; 19:9). The decision to return through Macedonia rather than sail directly from Corinth to Syria reflects genuine security concerns — a ship passage through the Aegean offered ambush opportunities at embarkation points. The rerouting adds weeks to the journey but removes the threat.</p>",
"4": "<p>The list of companions accompanying Paul to Jerusalem with the collection (cf. 1 Cor 16:3–4; 2 Cor 8–9; Rom 15:25–28) represents the geographical breadth of the Gentile mission: Sopater of Berea (Macedonia), Aristarchus and Secundus of Thessalonica (Macedonia), Gaius of Derbe and Timothy (Galatia/South Asia Minor), and Tychicus and Trophimus of Asia. These men likely served as official delegates from their communities, carrying the collection funds and giving it legal standing as a communal gift rather than a personal transfer.</p>",
"5": "<p>The 'we' narrative resumes here after the gap since Acts 16:17 — Luke rejoins the party at Philippi (cf. 16:40, where the 'we' dropped out after Paul's departure). The resumption 'these men went ahead and waited for us at Troas' indicates Luke traveled separately from the main group, meeting at the familiar Troas transit point (cf. 16:8–11). The five days from Philippi to Troas (contrast the two-day favorable crossing of 16:11) suggests adverse winds.</p>",
"6": "<p>The 'days of Unleavened Bread' (Azymōn) — the week of Passover — situates this journey in the spring calendar, consistent with Paul's goal of reaching Jerusalem by Pentecost (v. 16). Passover to Pentecost is fifty days; the seven-day stay at Troas plus subsequent travel to Jerusalem fits the timeline. The voyage from Philippi/Neapolis to Troas taking five days (vs. two days on the second journey, Acts 16:11) suggests headwinds on the Aegean — a common spring sailing challenge.</p>",
"7": "<p>The gathering 'on the first day of the week' (tē mia tōn sabbatōn) is an early attestation of Christian Sunday worship — the day of resurrection rather than the Jewish Sabbath. 'Breaking bread' (klasai arton) was the standard early Christian term for the Eucharistic meal (cf. 2:42, 46; 1 Cor 10:16; 11:20–34). The evening setting suggests the meeting followed the Jewish day reckoning (evening to evening) or simply that the community met after the work day. The extended discourse until midnight (mechri mesonyktiou) reflects Paul's awareness that this would be his last visit — he speaks at unusual length.</p>",
"8": "<p>The 'many lamps' (lampades hikanai) in the upper room (hyperōō) serve both practical and narrative functions — they explain the drowsy atmosphere (heat, late hour, packed room) and establish the setting for Eutychus's fall. The upper room (hyperōon) was the standard meeting space for the early Jerusalem community (1:13) and here appears in Troas. The domestic setting — a third-floor apartment in a multistory building — is consistent with urban Hellenistic housing in a port city.</p>",
"9": "<p>Eutychus ('Lucky' — a common slave name meaning fortunate) sat in the window (thyridi) and fell from the third floor (apo tou tristegou). Ancient multistory buildings in port cities like Troas could be three or four stories — the fall from the third story (tristegon) would typically be fatal. The young man (neanias) is described as 'overcome by sleep' (katapheromenos hypnō bathei) during Paul's discourse — a detail that humanizes the narrative while excusing neither Paul's length nor the congregation's drowsiness.</p>",
"10": "<p>Paul's gesture — 'falling on him and embracing him' (epipesōn ... synperielaben) — deliberately echoes Elijah's action over the widow's son (1 Kgs 17:21) and Elisha's over the Shunammite's son (2 Kgs 4:34). The parallel marks Paul as a prophet in the succession of Israel's great miracle-workers. 'His life is in him' (hē psychē autou en autō estin) is the announcement of restoration — the community's response ('they were not a little comforted,' v. 12) confirms the miracle.</p>",
"11": "<p>After the miracle, the breaking of bread (klasas ton arton) and extended conversation (homilēsas epi poly — 'talked extensively') until dawn complete the vigil. The Eucharistic meal appears to follow the miracle rather than precede it — the celebration of resurrection life in the assembly is enacted immediately after a literal restoration of life. Paul departs at dawn, having kept the community through a full night of worship, word, and miracle.</p>",
"12": "<p>The community takes Eutychus home alive (zōnta) — Luke's emphasis. The word 'comforted' (pareклēthēsan) — paraklēthēsan — echoes Paul's own mission vocabulary (parakaleō, v. 1) and the title of the Spirit in John's Gospel. The Troas community that began with Paul's vision of a Macedonian man calling him (Acts 16:9) is now consolidated with this dramatic pastoral encounter — a church that will have this story as a founding narrative.</p>",
"13": "<p>The coastal journey from Troas to Assos on foot (about 30 km) while the ship went around the cape was deliberate — Paul 'had so arranged' (diatetagmenos) this for himself. The reason is not given; possibly Paul wanted time alone before the intense Jerusalem journey, possibly pastoral business in the interior. Assos was a port city in the Troad with a significant harbor — the ship picked Paul up there for the coastal voyage south.</p>",
"14": "<p>The coastal itinerary from Assos through Mitylene (Lesbos), Chios, Samos, and Miletus follows the standard Aegean coastal shipping lanes — ancient vessels hugged the coast rather than crossing open water where possible. The geography is precise: Mitylene was the main city of Lesbos, Chios was the island opposite the Asian coast, Samos was the island closest to Miletus/Ephesus. Luke's navigational detail in these verses reflects the 'we' eyewitness source.</p>",
"15": "<p>The stops at Chios and Samos mark the approach to the Ionian coast. The 'next day we arrived at Miletus' — bypassing Ephesus (v. 16) — placed Paul at the major port city of the southern Ionian coast. Miletus had been one of the great cities of archaic Greece and remained a significant commercial port in Roman Asia Minor, with a large harbor and substantial civic infrastructure. Its distance from Ephesus (about 50 km) was close enough for the elders to reach in a day or two.</p>",
"16": "<p>Paul's decision to bypass Ephesus — where he had spent three years (v. 31) — is explained by the Pentecost deadline. The fifty days between Passover and Pentecost created a fixed travel window; a stop at Ephesus would have been extended by the inevitable pastoral demands of the community. The Miletus stopover achieved the same purpose — meeting the Ephesian leadership — without the city's entanglements. Pentecost was a pilgrimage festival; Paul's urgency to be in Jerusalem for it reflects both personal devotion and the symbolic significance of the Spirit's arrival at the first Pentecost (Acts 2).</p>",
"17": "<p>The summons to the 'elders' (presbyterous) of the church at Ephesus is the only speech in Acts addressed exclusively to Christian leaders rather than to Jewish or pagan audiences. The elders (presbyteroi) of Ephesus appear to be synonymous with 'overseers' (episkopous) in v. 28 — the two terms were interchangeable in early church usage (cf. Phil 1:1; Titus 1:5–7). The Miletus address is Paul's pastoral testament, delivered in anticipation of his death (vv. 22–25).</p>",
"18": "<p>'You yourselves know' (hymeis epistasthe) — Paul's self-defense mode, appealing to the elders' direct knowledge as his testimonial. His description of his Ephesian ministry emphasizes consistency ('from the first day I set foot in Asia') and character ('serving the Lord with all humility'). The Ephesian period (approximately AD 52–55) was Paul's longest sustained ministry in one city, the anchor of his Asian mission, and the base from which the surrounding region heard the word (19:10).</p>",
"19": "<p>Paul's description of 'serving with tears and through trials from the plots of the Jews' (meta dakryōn kai peirasmōn ... epibolōn tōn Ioudaiōn) corresponds to the Ephesian narrative (19:9, 33; cf. 2 Cor 11:24–28; 1 Cor 15:32 — fighting 'wild beasts at Ephesus'). The emotional register ('tears') is unusual for Luke's Paul — the Miletus address repeatedly mentions tears (vv. 19, 31, 37) as the marker of genuine pastoral investment rather than mercenary service.</p>",
"20": "<p>'I did not shrink from declaring to you anything that was profitable' (ouk hypesteilamēn tōn symphrontōn) — the language of not suppressing difficult truths is the mark of a faithful messenger (cf. Ezek 33:7–9). The combination of 'public' (dēmosiai) and 'house to house' (kat' oikous) teaching reflects the dual-venue model of Acts: synagogue/public space plus domestic gatherings. The Ephesian church's house-church structure (cf. 1 Cor 16:19 — Aquila and Prisca's church at Ephesus) gave the mission its residential texture.</p>",
"21": "<p>'Testifying both to Jews and to Greeks of repentance toward God and of faith in our Lord Jesus Christ' is the core Pauline kerygmatic formula — applicable to both Jewish and Gentile audiences, requiring the same response. Metanoia (repentance) directed 'toward God' is the Jewish covenant category; pistis (faith) 'in our Lord Jesus Christ' is the specifically Christian addition. The bipartite formula — toward God, through Christ — captures the theological continuity (Jewish repentance tradition) and discontinuity (the new agent of reconciliation).</p>",
"22": "<p>'Bound in the Spirit' (dedemenos egō tō pneumati) uses the language of compulsion — Paul is under a binding that overrides his own preferences. The Spirit is the agent of the Jerusalem journey (cf. 19:21 — Paul 'resolved in the Spirit'). The ignorance of what awaits him ('not knowing what will happen to me there') is then immediately modified by the prophetic warnings of vv. 23 — the Spirit reveals the suffering but not the specific details, enough to test Paul's resolve but not to determine his itinerary.</p>",
"23": "<p>'The Holy Spirit testifies to me in every city that imprisonment and afflictions await me' — the prophetic warnings in every city parallel the prophetic word through Agabus in Acts 21:10–11 and the disciples at Tyre (21:4). Paul's awareness of impending suffering is the context for his statement in v. 24 — he is not ignorant of the cost, but counts it worth paying. This fulfills Jesus's prediction at Paul's call: 'I will show him how much he must suffer for the sake of my name' (Acts 9:16).</p>",
"24": "<p>'I do not account my life of any value to myself' (all' oudenos logou poioumai tēn psychēn timian emautō) is Paul's explicit statement of martyrdom readiness — the psychē (life/soul) held loosely in comparison to the mission. 'The ministry I received from the Lord Jesus to testify to the gospel of the grace of God' frames the mission as received rather than chosen — a trust (diakonia) entrusted by the Lord that Paul is obligated to complete. The language echoes his self-description in Galatians 1:1 and Romans 15:15–16.</p>",
"25": "<p>'None of you among whom I have gone about proclaiming the kingdom will see my face again' — Paul's farewell prophecy. The 'kingdom of God' (tēn basileian) is the Lukan summary of Paul's proclamation (cf. 28:31), a comprehensive term for the eschatological reign Christ inaugurated. Whether this prophecy was fulfilled literally has been debated — Acts does not record a return to Ephesus, though some scholars argue the Pastoral Epistles presuppose a later Ephesian visit. Within Luke's narrative, this is a formal farewell.</p>",
"26": "<p>'I am innocent of the blood of all of you' (katharos eimi apo tou haimatos pantōn hymōn) echoes Ezekiel 3:17–21 and 33:1–9 — the watchman who warns the city is released from guilt when the people ignore the warning. The idiom of blood-guilt goes back to Israel's legal tradition (Deut 19:10; 2 Sam 1:16). Paul's self-justification is not self-congratulation but a legal declaration of cleared responsibility — he has been faithful to the warning commission.</p>",
"27": "<p>'The whole counsel of God' (pasan tēn boulēn tou theou) — the boulē of God is the divine plan comprehensively — not a selective presentation tailored to audience comfort but the full scope of God's purposes, including judgment, repentance, and the scandal of the cross. The elder who 'holds firm to the trustworthy word as taught' (Titus 1:9) is the embodiment of this standard; Paul models the courage required to proclaim the whole counsel without suppression.</p>",
"28": "<p>'Pay careful attention to yourselves and to all the flock, in which the Holy Spirit has made you overseers' (episkopous) — the Spirit's appointment of church leadership, not merely human appointment, is the ground of pastoral authority. The 'flock' metaphor (poimnion) is consistent with Jewish (Ps 100:3; Jer 23:1–4) and early Christian (John 10; 1 Pet 5:2–4) shepherd imagery. 'The church of God which he obtained with his own blood' — the possessive clause grounds pastoral care in the price paid for the flock: the blood of Christ.</p>",
"29": "<p>'Fierce wolves' (lykoi bareis) who 'come in among you not sparing the flock' — the wolf metaphor for false teachers enters the tradition at Matthew 7:15 and 10:16 and recurs in Christian pastoral literature. Paul's prediction anticipates the Ephesian situation addressed in the Pastoral Epistles (1 Tim 1:3–7; 2 Tim 1:15; 4:3–4; Rev 2:1–7) — false teachers who arose from within the Ephesian community within a generation of Paul's departure, fulfilling the dual prophecy of vv. 29–30.</p>",
"30": "<p>'From among your own selves men will arise speaking twisted things to draw away the disciples after them' — the internal origin of the false teachers is the more dangerous threat. External wolves can be identified; internal distortions arise from the established leadership itself. The Ignatian letters (c. AD 107–110) to Ephesus confirm Paul's prediction: Ignatius writes commending the Ephesian church for rejecting heretics but warns of ongoing danger. The Ephesian church's discernment (Rev 2:2 — 'you have tested those who call themselves apostles') confirms the pattern.</p>",
"31": "<p>'Therefore be alert' (grēgoreite) — the imperative of the watchman tradition (Ezek 33; 1 Thess 5:6; 1 Pet 5:8; Rev 3:2). Paul grounds the call to vigilance in his own three-year example: 'for three years I did not cease night or day to admonish every one with tears.' The tears recur (cf. v. 19, 37) as the marker of genuine pastoral investment. The three-year period corresponds to Acts 19's Ephesian ministry — Paul's longest single-city residence in the narrative.</p>",
"32": "<p>'I commend you to God and to the word of his grace' (tō theō kai tō logō tēs charitos autou) — Paul entrusts the Ephesian elders not to a successor leader but to God and the written/proclaimed word. This word 'is able to build you up and give you an inheritance among all those who are sanctified' — the word's efficacy without Paul's physical presence. The formulation anticipates the post-apostolic period when the community would depend on preserved teaching rather than living apostolic presence.</p>",
"33": "<p>'I coveted no one's silver or gold or clothing' — the standard self-defense against charges of mercenary ministry (cf. 1 Thess 2:5; 2 Cor 12:17–18; 1 Cor 9). Itinerant teachers and philosophers in antiquity were routinely suspected of exploiting their audiences for financial gain — the Sophists' fees were a standing controversy. Paul's refusal of financial support from communities while among them (though accepting it when absent — cf. Phil 4:15–16) was a deliberate strategy to undercut this accusation.</p>",
"34": "<p>'These hands ministered to my necessities and to those who were with me' — Paul's manual labor as self-support is attested throughout his letters (1 Cor 4:12; 2 Thess 3:8; Phil 4:14–18) and by the Aquila-Priscilla tent-making partnership of Acts 18:3. The display of his hands — or the gesture toward them — is a physical demonstration accompanying the verbal claim, a rhetorically effective move before an audience who knew him personally and could verify it.</p>",
"35": "<p>'The words of the Lord Jesus how he said, It is more blessed to give than to receive' — this is the only explicit quotation of a saying of Jesus not found in the canonical Gospels. Such agrapha (unwritten sayings) were known in early Christianity; Paul's citation suggests a tradition of Jesus-sayings circulating independently of the written Gospels. The saying encapsulates the entire financial ethics of vv. 33–35 and grounds it in dominical authority.</p>",
"36": "<p>Paul kneels and prays with the elders — kneeling prayer (theis ta gonata autou) was reserved for the most solemn supplications in Jewish and early Christian practice (cf. Dan 6:10; Eph 3:14; Luke 22:41). The corporate prayer seals the pastoral testament and anticipates the farewell lament that follows. The gesture communicates the gravity of the moment — this is not a routine pastoral visit but a final commissioning.</p>",
"37": "<p>'They all wept aloud and embraced Paul and kissed him' (klauthmos ... epipesontes ... katephiloun) — the emotional intensity of the Miletus farewell is unparalleled in Acts. The verb kataphileō (kissed repeatedly, affectionately) and the falling on Paul's neck echo Genesis 45:14–15 (Joseph's reunion with Benjamin and his brothers) and Luke 15:20 (the father's welcome of the prodigal). The communal grief marks the depth of the pastoral relationship Paul had built over three years.</p>",
"38": "<p>'Grieving especially because of the word he had spoken, that they would not see his face again' — the specific cause of grief is Paul's farewell prophecy (v. 25). The departure by ship — they 'accompanied him to the ship' — marks the physical severance. Luke's attention to this farewell scene, the most emotionally detailed in Acts, signals its theological importance: the apostolic age is closing, and the community must now sustain itself on the inherited word and appointed leadership."
},
"21": {
"1": "<p>The voyage from Miletus proceeds by island-hopping — Cos, Rhodes, and Patara — the standard coastal route from the Ionian coast south and east. Cos was a major island with a famous Asklepion (healing sanctuary); Rhodes was the dominant island of the Aegean's southern approaches; Patara was a major port city of Lycia on the southern coast of Asia Minor, the embarkation point for direct crossings to the Levantine coast.</p>",
"2": "<p>At Patara the party transfers from a coastal vessel to a direct Phoenician ship — a larger merchant vessel that could make the open-water crossing directly to the Syrian/Phoenician coast. The straight crossing from Patara to Tyre would take several days, passing south of Cyprus — the route Paul had traversed in the opposite direction on his first journey (Acts 13:4). The change of vessel reflects the different shipping routes: coastal vessels hugged the shore; direct-crossing merchants had different routes and schedules.</p>",
"3": "<p>Cyprus appears to the left (kataleipō) — the party sails past rather than stopping, maintaining the direct route to Syria. Tyre (modern Sur, Lebanon) was a major Phoenician port and one of the oldest continuously inhabited cities in the ancient world. The ship's unloading of cargo (apophortizomenon ton gomon) required a week in port — giving Paul and his party an unexpected week with the Tyrian Christian community, the origin of which is unknown in Acts but presumably dates to the Hellenist diaspora of Acts 11:19.</p>",
"4": "<p>'Through the Spirit they told Paul not to go on to Jerusalem' — the prophetic prohibition raises a tension with Paul's Spirit-compelled journey (20:22). The resolution is that the Spirit reveals the suffering that awaits (cf. 20:23; 21:10–11) and the community responds with loving prohibition — they are not wrong about the Spirit's content but misread the appropriate response. Paul's martyrdom-readiness (20:24) means that the same Spirit-revelation calls him forward while others respond with protective caution.</p>",
"5": "<p>The farewell scene at Tyre — kneeling on the beach in prayer with the whole community including 'wives and children' — mirrors the Miletus farewell's emotional register. The beach setting (eis ton aigialon) adds visual drama. Kneeling prayer publicly, with entire families, marks the solemnity of the departure in a way that the surrounding civic culture (which associated kneeling with subordination or supplication) would have recognized as extraordinary communal devotion.</p>",
"6": "<p>The embarkation and return home by the community mirrors the Miletus farewell (20:38). The pattern of farewell with prayer and return to life is a pastoral enactment of the apostolic commission's cost — the community knows they may not see Paul again. Luke's repeated attention to these departure scenes builds the cumulative weight of the Jerusalem journey's finality.</p>",
"7": "<p>Ptolemais (modern Akko/Acre, Israel) was the last major port before Caesarea, a former Ptolemaic stronghold that had become a major city in the northern coastal region. The greeting of 'the brothers' (tous adelphous) there with a one-day stay implies a small but established Christian community, again of unknown origin — part of the wider Levantine Christian network that the Hellenist diaspora had established (cf. 11:19).</p>",
"8": "<p>Caesarea Maritima was the Roman administrative capital of Judea — Herod's purpose-built city with an artificial harbor (Sebastos — named for Augustus), a palace, a theater, an amphitheater, and the residence of the Roman governor. Philip the Evangelist — one of the Seven (Acts 6:5; 8:4–40) — had settled here after his Samaritan and Azotus/coastal mission. His presence in Caesarea closes a narrative loop: the last Hellenist leader seen in Acts appears as Paul's host before the Jerusalem crisis.</p>",
"9": "<p>Philip's four daughters who prophesied (parthenoi tessares prophēteuousai) are significant: they fulfill Joel 2:28's promise (quoted at Pentecost, Acts 2:17 — 'your daughters will prophesy') and attest to the ongoing prophetic gift in the church without being named or individuated. The specification that they were unmarried (parthenoi — virgins) may reflect the association of prophetic charism with dedicated celibacy in some early Christian contexts (cf. 1 Cor 7:34). Their prophecy is not quoted — Luke notes the gift without recording the content.</p>",
"10": "<p>Agabus 'came down from Judea' — the same prophet who had predicted the Judean famine in Acts 11:28. His reappearance links this Jerusalem crisis to the first major Jewish-Gentile relief action of the church and confirms his established prophetic reputation. The formal prophetic act — tying his own hands and feet with Paul's belt — is a symbolic action in the OT prophetic tradition (cf. Isaiah 20:2–3; Jer 13:1–11; Ezek 4:1–8), enacting what the prophet announces rather than merely speaking it.</p>",
"11": "<p>'Thus says the Holy Spirit, the man who owns this belt will be bound like this in Jerusalem and delivered into the hands of the Gentiles' — the formula 'thus says the Holy Spirit' (tade legei to pneuma to hagion) echoes OT prophetic formulae ('thus says the LORD'). The prediction is structurally accurate: Paul was bound by a Roman tribune (v. 33) and subsequently transferred to Gentile (Roman) custody — not literally by Jews, but through Jewish instigation leading to Roman arrest. The prophecy is fulfilled with interpretive latitude consistent with OT prophetic fulfillment patterns.</p>",
"12": "<p>The combined pleading by Paul's companions ('we') and the local Caesarean community mirrors the Tyre episode (v. 4) — loving protective response to prophetic warning. The communal character of the plea reflects the early church's understanding of apostolic lives as community property, not merely personal choices. Paul's decision to proceed overrides communal discernment — not because the community is wrong but because Paul has a higher calling that embraces the suffering they fear for him.</p>",
"13": "<p>'What are you doing, weeping and breaking my heart?' — Paul's response is emotional engagement with their grief, not dismissal. 'I am ready not only to be imprisoned but even to die in Jerusalem for the name of the Lord Jesus' — the martyrdom formula explicitly stated. The 'name' (onoma) of the Lord Jesus is the theological axis of the entire Acts narrative (3:6; 4:10; 5:41; 9:16; 15:26) — Paul's readiness to die 'for the name' is the ultimate expression of the mission's cost and significance.</p>",
"14": "<p>'The Lord's will be done' (tou kyriou to thelēma ginesthō) echoes the Lord's Prayer and Gethsemane (Matt 6:10; 26:42; Luke 22:42). The community's eventual acquiescence — 'we were silenced' — is not resignation but submission to a will higher than their protective instinct. This is the resolution of the Spirit-prohibition tension: the Spirit warns, the community responds protectively, but Paul's martyrdom-readiness is itself Spirit-directed, and the community ultimately recognizes this.</p>",
"15": "<p>'After these days we got ready and went up to Jerusalem' — the 'we' narrative continues through Paul's arrival. 'Getting ready' (episkevasamenos) likely refers to arranging travel provisions and perhaps the collection funds being organized for presentation. The ascent to Jerusalem (anabainein eis Hierosolyma) uses the standard topographical term — Jerusalem at 800m elevation required literal ascent from the coastal plain and coastal cities.</p>",
"16": "<p>Mnason of Cyprus, 'an early disciple' (archaiō mathētē), provides lodging in Jerusalem. The specification 'early disciple' suggests he had been a follower since the earliest Jerusalem period, possibly since Pentecost — a first-generation believer now serving as host in the city where the movement began. Cyprus-origin connects to Barnabas (4:36) and the Hellenist missionaries of 11:19–20. His willingness to host Paul and a large Gentile party required courage given the Jerusalem community's tensions with Paul's mission.</p>",
"17": "<p>The Jerusalem community's welcome (apedexanto hēmas) is formally warm. The delegation with the Gentile collection has arrived in the holy city — the climax of Paul's third journey and the fulfillment of the collection project (Rom 15:25–28). Luke does not explicitly mention the collection's reception, a notable omission that may reflect the collection's complicated reception or Luke's narrative focus on the subsequent events.</p>",
"18": "<p>James (the brother of the Lord) remains the leader of the Jerusalem church — consistent with his role since Acts 15 and confirmed by Paul's letters (Gal 1:19; 2:9, 12; 1 Cor 15:7). 'All the elders' (pantes hoi presbyteroi) — the plural leadership structure of the Jerusalem church, without Peter (who has been absent from Acts since 15:7). James's position is monarchical in practice; the elders serve as his council. This is the last meeting between Paul and the Jerusalem leadership in Acts.</p>",
"19": "<p>Paul's report — 'he related one by one the things that God had done among the Gentiles through his ministry' — is the third Jerusalem report in Acts (cf. 14:27; 15:4, 12). Each report functions as an accountability moment between the Gentile mission and the mother church. 'One by one' (kath' hen hekaston) suggests a detailed, ordered account — possibly the same material compressed in Acts 19–20. The community glorified God (edoxazon ton theon) on hearing it.</p>",
"20": "<p>The Jerusalem elders immediately present the tension: 'You see, brother, how many thousands of Jewish believers there are, and all of them are zealous for the law' (zēlōtai tou nomou). The 'myriads' (myriai — ten-thousands) of Jewish believers are Torah-observant — the Jerusalem church had not abandoned Jewish practice. The sociological reality of the Jerusalem community — deeply embedded in Jewish piety, law, and temple practice — creates the structural context for the concern about Paul's reputation (v. 21).</p>",
"21": "<p>The charge against Paul — 'that you teach all the Jews who are among the Gentiles to forsake Moses, telling them not to circumcise their children or walk according to our customs' — is the defining controversy of Paul's mission. Whether this was accurate depends on what Paul taught: he taught that circumcision was not required for salvation (Gal 5:2; 1 Cor 7:18–19) but does not appear to have actively taught diaspora Jews to abandon Torah practice. The misrepresentation (or simplification) of Paul's teaching had reached Jerusalem and created a reputation problem that the elders needed to address.</p>",
"22": "<p>The elders' question — 'what is to be done?' — acknowledges the political reality that Paul's Jerusalem presence would trigger a confrontation with the Torah-zealot Jewish Christians. The proposed solution (vv. 23–24) is pragmatic: a public demonstration of Paul's own Jewish piety through a Nazirite vow sponsorship would counter the reputation without requiring doctrinal concession.</p>",
"23": "<p>The Nazirite vow (Num 6:1–21) required abstinence from wine, not cutting hair, and avoiding corpse impurity for a designated period, concluded by head-shaving and temple sacrifices. Four men with a vow already in progress needed a sponsor to pay for the required sacrifices — a recognized act of Jewish piety (cf. Josephus, Ant. 19.294, where Agrippa I sponsored such vows). Paul's sponsorship would require him to undergo purification himself and present offerings at the temple — a visible act of Jewish worship practice.</p>",
"24": "<p>'Take these men and purify yourself along with them and pay their expenses' — Paul's own purification rites (hagnisthēti syn autois) likely referred to a seven-day purification period for anyone who had incurred Levitical impurity (Num 19:12), which extended travel would have involved. The elders' goal: 'all will know that there is nothing in what they have been told about you, but that you yourself also live in observance of the law.' The sponsorship is a public gesture, not a private theological position.</p>",
"25": "<p>The elders reaffirm the Jerusalem decree (Acts 15:28–29) for Gentile believers — confirming that the vow sponsorship applies only to Jewish Christians and does not alter the Gentile mission's Torah-free character. The distinction between Jewish Christians (who continued Torah observance) and Gentile Christians (who were not required to) was the practical resolution of the Jerusalem council — maintained here as the operating agreement.</p>",
"26": "<p>Paul complies — taking the men the next day, undergoing purification, announcing the completion date, and arranging for the sacrifices. The compliance is remarkable: Paul, who wrote Galatians 5:2 ('if you receive circumcision, Christ will be of no advantage to you') was willing to sponsor Nazirite vows in the Jerusalem temple. The apparent tension was navigated in 1 Corinthians 9:20 — Paul's principle of becoming 'as a Jew to Jews ... so that by all means I might save some.' The vow sponsorship was an act of cultural accommodation, not theological capitulation.</p>",
"27": "<p>'When the seven days were almost completed' — the purification period was nearly finished when the crisis erupted. 'Jews from Asia' (hoi apo tēs Asias Ioudaioi) — probably Ephesian Jews who recognized Paul and Trophimus from the Ephesian synagogue confrontation (Acts 19:9). The phrase 'stirred up the whole crowd' (synecheōn panta ton ochlon) — the same crowd-agitation dynamic that operated at Thessalonica (17:5) and Ephesus (19:29). The timing — the public temple courts during Pentecost — ensured maximum audience for the accusation.</p>",
"28": "<p>The charge has two components: 'This is the man who is teaching everyone everywhere against the people and the law and this place' — the same threefold charge as Stephen's accusers (Acts 6:13–14: against the holy place and the law). The second component is the lethal accusation: 'and furthermore he has even brought Greeks into the temple and has defiled this holy place.' The gentile exclusion boundary was physically enforced by stone inscriptions (two complete examples survive from excavations) warning that any non-Jew who passed the soreg (barrier) would be killed. The accusation of temple defilement by Gentile entry was legally a capital offense.</p>",
"29": "<p>The factual basis for the accusation: the Asian Jews had seen Trophimus the Ephesian (one of Paul's companions, Acts 20:4) with Paul in the city and assumed he had brought him into the temple. The assumption was false — Paul had brought no one past the Court of the Gentiles — but the inference was plausible given their association in the city. False accusation based on plausible inference is the mechanism of most of Paul's subsequent legal troubles.</p>",
"30": "<p>The city is 'stirred up' (ekinēthē hē polis holē) and 'the people ran together' (sundromē tou laou) — the Pentecost crowd in Jerusalem was at peak density, making a mob disturbance potentially massive. Paul is dragged from the temple (eilkon auton exō tou hierou) and the gates are shut (ekleisthēsan hai thyrai) — the temple guards closing the sanctuary against the mob violence, preventing desecration of the holy space by bloodshed within it. The irony: the temple closes its doors on the man they accuse of desecrating it.</p>",
"31": "<p>The tribune (chiliarchos — commander of a thousand, the Roman military tribune) learns of the riot and brings soldiers and centurions immediately. The Antonia fortress, Herod's tower at the northwest corner of the temple mount, gave direct access to the temple courts via stairs (v. 40). The Roman military presence in Jerusalem during festivals was deliberately heightened — Josephus describes the practice of stationing extra troops on the porticoes during Passover and Pentecost to prevent exactly this kind of riot (Jewish War 2.224).</p>",
"32": "<p>The tribune's rapid descent with soldiers and centurions (plural — a substantial force) stops the beating immediately. The crowd 'stopped beating Paul' (epausanto typtōntes) when they saw the military — the Roman presence as the guarantor of order that paradoxically protects Paul from the Jewish mob that will subsequently demand his death. The tribune's intervention establishes the pattern of Roman custody as Paul's protection for the remainder of Acts.</p>",
"33": "<p>The binding with 'two chains' (halysesin dysin) — Roman custody required chaining a prisoner between two soldiers, one chain on each wrist. The tribune's demand to know who Paul was and what he had done reflects standard Roman procedure: establish identity and offense before any decision. The mob's contradictory shouts — everyone calling out different things — prevent coherent information gathering, triggering the decision to bring Paul into the barracks for examination.</p>",
"34": "<p>The 'barracks' (parembolēn) is the Antonia fortress — the Roman military headquarters adjacent to the temple. The crowd's conflicting accusations make it impossible for the tribune to establish facts — Roman legal procedure required a coherent charge before any action. The inability to determine the truth from the mob's noise moves the legal proceedings inside Roman jurisdiction, where Paul will exercise his legal rights (chs. 22–26).</p>",
"35": "<p>The stairs connecting the temple mount to the Antonia fortress were the physical setting for Paul's address to the crowd (vv. 37–40; 22:1–21). 'Carried by the soldiers because of the violence of the crowd' — the mob pressed so close that the soldiers had to lift Paul bodily up the stairs to protect him. The scene's physical detail — typical of the 'we' eyewitness sections — captures the crush of a Jerusalem festival crowd with specific spatial geography.</p>",
"36": "<p>'Away with him!' (aire auton) — the same cry that the Jerusalem crowd had directed at Jesus (Luke 23:18; John 19:15; Acts 22:22). The echo is deliberate in Luke's theology: Paul's Jerusalem passion follows the pattern of Jesus's. The crowd's demand for Paul's elimination (aireō — remove, lift away, but also 'kill') mirrors the Barabbas episode and ties Paul's suffering to the master narrative of suffering for the name.</p>",
"38": "<p>The tribune's question — 'Are you not the Egyptian who recently stirred up a revolt and led the four thousand men of the Assassins out into the wilderness?' — references a historical figure known from Josephus (Jewish War 2.261–263; Ant. 20.169–172): an Egyptian prophet who led a group to the Mount of Olives, claiming the walls of Jerusalem would fall, who was dispersed by the governor Felix's troops. The four thousand 'Assassins' (sikariōn — sicarii, 'dagger men') were a violent anti-Roman faction; the tribune's confusion of Paul with this figure explains his military response to the riot.</p>",
"39": "<p>Paul's self-identification — 'a Jew from Tarsus in Cilicia, a citizen of no obscure city' (ouk asēmou poleōs politēs) — invokes civic pride (Tarsus was a major intellectual and commercial center, the seat of a Stoic philosophical school) and Jewish identity simultaneously. The request to 'address the people' (lalesai pros ton laon) is surprising: rather than retreating to Roman protection, Paul requests a public hearing from the crowd that had just been beating him. The request reveals Paul's understanding that this is a mission opportunity, not merely a legal crisis.</p>",
"40": "<p>The tribune gives permission; Paul 'beckoned with his hand' (kataseisas tē cheiri — the standard gesture for calling for silence in a public address, also used at 13:16; 26:1) and addresses the crowd 'in the Hebrew dialect' (tē Hebraidi dialektō — probably Aramaic, the common spoken form of 'Hebrew' in first-century Judea). The shift from Greek (the tribune's assumption, v. 37) to Aramaic creates 'a great quiet' (polē hēsychia) — the crowd's recognition that this was a Jew speaking their own language redirects hostility toward curiosity, the rhetorical opening for Acts 22."
}
}

def main():
    existing = load_comm('mkt-context', 'acts')
    merge_comm(existing, ACTS_CH)
    save_comm('mkt-context', 'acts', existing)
    for ck in ['20', '21']:
        count = len(existing.get(ck, {}))
        print(f'Acts {ck}: {count} verses.')

if __name__ == '__main__':
    main()
